import React, { useState, useEffect } from 'react';
import { 
  Container, 
  Box, 
  Paper, 
  Typography, 
  TextField, 
  Button, 
  Grid, 
  FormControl,
  InputLabel,
  Select,
  MenuItem,
  FormHelperText,
  Alert,
  CircularProgress,
  Stepper,
  Step,
  StepLabel,
  Card,
  CardContent,
  Divider
} from '@mui/material';
import { 
  Send, 
  AccountBalanceWallet, 
  Check, 
  Person
} from '@mui/icons-material';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';

const SendMoney = () => {
  const navigate = useNavigate();
  const [activeStep, setActiveStep] = useState(0);
  const [wallets, setWallets] = useState([]);
  const [loading, setLoading] = useState(true);
  const [sendingFunds, setSendingFunds] = useState(false);
  const [error, setError] = useState(null);
  const [success, setSuccess] = useState(false);
  const [transactionId, setTransactionId] = useState(null);
  const [formData, setFormData] = useState({
    sourceWalletId: '',
    recipientAddress: '',
    amount: '',
    currency: 'USD',
    description: ''
  });
  const [formErrors, setFormErrors] = useState({});
  const [conversionRate, setConversionRate] = useState(null);
  const [estimatedFee, setEstimatedFee] = useState(0);
  const [recipientInfo, setRecipientInfo] = useState(null);

  const steps = ['Select wallet', 'Enter recipient', 'Confirm transfer'];

  useEffect(() => {
    fetchWallets();
  }, []);

  // When source wallet or currency changes, update the conversion rate
  useEffect(() => {
    if (formData.sourceWalletId && formData.currency) {
      const selectedWallet = wallets.find(wallet => wallet.id === formData.sourceWalletId);
      if (selectedWallet && selectedWallet.currency !== formData.currency) {
        fetchConversionRate(selectedWallet.currency, formData.currency);
      } else {
        setConversionRate(null);
      }
    }
  }, [formData.sourceWalletId, formData.currency, wallets]);

  // Fetch wallets from the API
  const fetchWallets = async () => {
    setLoading(true);
    try {
      const response = await axios.get('/wallet/');
      setWallets(response.data);

      // If there are wallets, set the first one as the default source
      if (response.data.length > 0) {
        setFormData(prev => ({
          ...prev,
          sourceWalletId: response.data[0].id,
          currency: response.data[0].currency
        }));
      }
    } catch (err) {
      console.error('Error fetching wallets:', err);
      setError('Failed to load wallets. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  // Fetch conversion rate between currencies
  const fetchConversionRate = async (fromCurrency, toCurrency) => {
    if (fromCurrency === toCurrency) {
      setConversionRate(1);
      return;
    }

    try {
      const response = await axios.get(`/currency/rate/${fromCurrency}/${toCurrency}/`);
      setConversionRate(response.data.rate);
    } catch (err) {
      console.error('Error fetching conversion rate:', err);
      setConversionRate(null);
    }
  };

  // Look up recipient by address
  const lookupRecipient = async () => {
    if (!formData.recipientAddress) return;

    try {
      const response = await axios.get(`/wallet/lookup/${formData.recipientAddress}/`);
      setRecipientInfo(response.data);
      setFormErrors(prev => ({ ...prev, recipientAddress: null }));
    } catch (err) {
      console.error('Error looking up recipient:', err);
      setRecipientInfo(null);
      setFormErrors(prev => ({ 
        ...prev, 
        recipientAddress: 'Invalid recipient address' 
      }));
    }
  };

  // Calculate estimated fee
  const calculateFee = () => {
    // Simple fee calculation example - could be more complex in a real app
    const amount = parseFloat(formData.amount) || 0;
    const feeRate = 0.01; // 1%
    const calculatedFee = amount * feeRate;

    setEstimatedFee(calculatedFee);
    return calculatedFee;
  };

  // Validate the form data
  const validateForm = () => {
    const errors = {};

    if (!formData.sourceWalletId) {
      errors.sourceWalletId = 'Please select a source wallet';
    }

    if (!formData.recipientAddress) {
      errors.recipientAddress = 'Recipient address is required';
    }

    if (!formData.amount) {
      errors.amount = 'Amount is required';
    } else if (isNaN(formData.amount) || parseFloat(formData.amount) <= 0) {
      errors.amount = 'Amount must be a positive number';
    } else {
      // Check if source wallet has sufficient funds
      const selectedWallet = wallets.find(wallet => wallet.id === formData.sourceWalletId);
      if (selectedWallet) {
        const amountInSourceCurrency = formData.currency === selectedWallet.currency
          ? parseFloat(formData.amount)
          : parseFloat(formData.amount) / (conversionRate || 1);

        if (amountInSourceCurrency > parseFloat(selectedWallet.balance)) {
          errors.amount = 'Insufficient funds in the source wallet';
        }
      }
    }

    if (!formData.currency) {
      errors.currency = 'Currency is required';
    }

    setFormErrors(errors);
    return Object.keys(errors).length === 0;
  };

  // Handle form input changes
  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setFormData({
      ...formData,
      [name]: value
    });

    // Clear error when field is changed
    if (formErrors[name]) {
      setFormErrors({
        ...formErrors,
        [name]: null
      });
    }
  };

  // Handle recipient address change with debounce
  const handleRecipientChange = (e) => {
    const { value } = e.target;
    setFormData(prev => ({
      ...prev,
      recipientAddress: value
    }));

    // Clear recipient info when address changes
    setRecipientInfo(null);
  };

  // Handle form submission
  const handleSubmit = async () => {
    setSendingFunds(true);
    setError(null);

    try {
      const response = await axios.post('/transaction/', {
        source_wallet_id: formData.sourceWalletId,
        recipient_address: formData.recipientAddress,
        amount: parseFloat(formData.amount),
        currency: formData.currency,
        description: formData.description || 'Transfer'
      });

      setSuccess(true);
      setTransactionId(response.data.id);

      // Reset form
      setFormData({
        sourceWalletId: '',
        recipientAddress: '',
        amount: '',
        currency: 'USD',
        description: ''
      });
    } catch (err) {
      console.error('Error sending funds:', err);
      setError(err.response?.data?.detail || 'Failed to send funds. Please try again.');
    } finally {
      setSendingFunds(false);
    }
  };

  // Handle next step
  const handleNext = () => {
    if (activeStep === 0) {
      if (!formData.sourceWalletId) {
        setFormErrors(prev => ({ ...prev, sourceWalletId: 'Please select a source wallet' }));
        return;
      }
    } else if (activeStep === 1) {
      if (!validateForm()) {
        return;
      }
      calculateFee();
      lookupRecipient();
    } else if (activeStep === 2) {
      handleSubmit();
      return;
    }

    setActiveStep((prevActiveStep) => prevActiveStep + 1);
  };

  // Handle back step
  const handleBack = () => {
    setActiveStep((prevActiveStep) => prevActiveStep - 1);
  };

  // Format currency value
  const formatCurrency = (amount, currency = 'USD') => {
    return new Intl.NumberFormat('en-US', {
      style: 'currency',
      currency
    }).format(amount);
  };

  // Get selected wallet
  const getSelectedWallet = () => {
    return wallets.find(wallet => wallet.id === formData.sourceWalletId);
  };

  // Calculate the total amount (with fee)
  const calculateTotal = () => {
    const amount = parseFloat(formData.amount) || 0;
    return amount + estimatedFee;
  };

  if (loading) {
    return (
      <Box display="flex" justifyContent="center" alignItems="center" minHeight="80vh">
        <CircularProgress />
      </Box>
    );
  }

  if (success) {
    return (
      <Container maxWidth="md">
        <Paper sx={{ p: 4, mt: 4, textAlign: 'center' }}>
          <Check sx={{ fontSize: 80, color: 'success.main', mb: 2 }} />
          <Typography variant="h4" gutterBottom>
            Transfer Successful!
          </Typography>
          <Typography variant="body1" paragraph>
            Your transfer has been successfully initiated. Transaction ID: {transactionId}
          </Typography>
          <Box mt={4}>
            <Button 
              variant="contained" 
              color="primary" 
              onClick={() => navigate('/dashboard')}
            >
              Back to Dashboard
            </Button>
            <Button 
              variant="outlined" 
              sx={{ ml: 2 }}
              onClick={() => {
                setSuccess(false);
                setActiveStep(0);
              }}
            >
              Send Another Payment
            </Button>
          </Box>
        </Paper>
      </Container>
    );
  }

  return (
    <Container maxWidth="md">
      <Box sx={{ mt: 4, mb: 4 }}>
        <Paper sx={{ p: 3 }}>
          <Typography variant="h4" component="h1" gutterBottom>
            Send Money
          </Typography>

          <Stepper activeStep={activeStep} sx={{ mb: 4, mt: 3 }}>
            {steps.map((label) => (
              <Step key={label}>
                <StepLabel>{label}</StepLabel>
              </Step>
            ))}
          </Stepper>

          {error && (
            <Alert severity="error" sx={{ mb: 3 }}>
              {error}
            </Alert>
          )}

          {activeStep === 0 && (
            <Box>
              <Typography variant="h6" gutterBottom>
                Select Source Wallet
              </Typography>

              {wallets.length === 0 ? (
                <Box textAlign="center" py={3}>
                  <AccountBalanceWallet sx={{ fontSize: 60, color: 'text.secondary', mb: 2 }} />
                  <Typography variant="h6" gutterBottom>
                    No Wallets Found
                  </Typography>
                  <Typography variant="body1" color="text.secondary" paragraph>
                    You need to create a wallet before you can send funds.
                  </Typography>
                  <Button 
                    variant="contained" 
                    onClick={() => navigate('/wallets/new')}
                  >
                    Create Wallet
                  </Button>
                </Box>
              ) : (
                <Grid container spacing={3}>
                  {wallets.map((wallet) => (
                    <Grid item xs={12} sm={6} key={wallet.id}>
                      <Card 
                        sx={{ 
                          cursor: 'pointer',
                          border: formData.sourceWalletId === wallet.id ? 2 : 0,
                          borderColor: 'primary.main',
                          transition: 'all 0.3s'
                        }}
                        onClick={() => setFormData(prev => ({ 
                          ...prev, 
                          sourceWalletId: wallet.id,
                          currency: wallet.currency
                        }))}
                      >
                        <CardContent>
                          <Typography variant="h6" gutterBottom>
                            {wallet.name}
                          </Typography>
                          <Typography variant="h5" component="div">
                            {formatCurrency(wallet.balance, wallet.currency)}
                          </Typography>
                          <Typography color="text.secondary" sx={{ mt: 1 }}>
                            Address: {wallet.address.substring(0, 10)}...
                          </Typography>
                        </CardContent>
                      </Card>
                    </Grid>
                  ))}
                </Grid>
              )}

              {formErrors.sourceWalletId && (
                <FormHelperText error>{formErrors.sourceWalletId}</FormHelperText>
              )}
            </Box>
          )}

          {activeStep === 1 && (
            <Box>
              <Typography variant="h6" gutterBottom>
                Enter Recipient Details
              </Typography>

              <Grid container spacing={3}>
                <Grid item xs={12}>
                  <TextField
                    fullWidth
                    label="Recipient Address"
                    name="recipientAddress"
                    value={formData.recipientAddress}
                    onChange={handleRecipientChange}
                    error={!!formErrors.recipientAddress}
                    helperText={formErrors.recipientAddress}
                    onBlur={lookupRecipient}
                  />
                </Grid>

                {recipientInfo && (
                  <Grid item xs={12}>
                    <Alert severity="info" icon={<Person />}>
                      Recipient: {recipientInfo.username || recipientInfo.name || 'Unknown User'}
                    </Alert>
                  </Grid>
                )}

                <Grid item xs={12} sm={6}>
                  <TextField
                    fullWidth
                    label="Amount"
                    name="amount"
                    type="number"
                    value={formData.amount}
                    onChange={handleInputChange}
                    error={!!formErrors.amount}
                    helperText={formErrors.amount}
                    InputProps={{
                      inputProps: { min: 0, step: "0.01" }
                    }}
                  />
                </Grid>

                <Grid item xs={12} sm={6}>
                  <FormControl fullWidth error={!!formErrors.currency}>
                    <InputLabel id="currency-select-label">Currency</InputLabel>
                    <Select
                      labelId="currency-select-label"
                      id="currency-select"
                      name="currency"
                      value={formData.currency}
                      onChange={handleInputChange}
                      label="Currency"
                    >
                      <MenuItem value="USD">USD</MenuItem>
                      <MenuItem value="EUR">EUR</MenuItem>
                      <MenuItem value="GBP">GBP</MenuItem>
                      <MenuItem value="CAD">CAD</MenuItem>
                      <MenuItem value="JPY">JPY</MenuItem>
                      <MenuItem value="USDC">USDC</MenuItem>
                      <MenuItem value="USDT">USDT</MenuItem>
                      <MenuItem value="ETH">ETH</MenuItem>
                      <MenuItem value="BTC">BTC</MenuItem>
                    </Select>
                    {formErrors.currency && (
                      <FormHelperText>{formErrors.currency}</FormHelperText>
                    )}
                  </FormControl>
                </Grid>

                <Grid item xs={12}>
                  <TextField
                    fullWidth
                    label="Description (Optional)"
                    name="description"
                    value={formData.description}
                    onChange={handleInputChange}
                    multiline
                    rows={2}
                  />
                </Grid>
              </Grid>

              {conversionRate && formData.amount && (
                <Alert severity="info" sx={{ mt: 3 }}>
                  You're sending {formatCurrency(formData.amount, formData.currency)}. 
                  This will convert to approximately {formatCurrency(
                    parseFloat(formData.amount) / conversionRate, 
                    getSelectedWallet()?.currency
                  )} from your wallet.
                </Alert>
              )}
            </Box>
          )}

          {activeStep === 2 && (
            <Box>
              <Typography variant="h6" gutterBottom>
                Review and Confirm
              </Typography>

              <Card sx={{ mb: 3 }}>
                <CardContent>
                  <Grid container spacing={2}>
                    <Grid item xs={6}>
                      <Typography variant="subtitle2" color="text.secondary">
                        From
                      </Typography>
                      <Typography variant="body1">
                        {getSelectedWallet()?.name}
                      </Typography>
                      <Typography variant="body2" color="text.secondary">
                        {getSelectedWallet()?.address.substring(0, 10)}...
                      </Typography>
                    </Grid>

                    <Grid item xs={6}>
                      <Typography variant="subtitle2" color="text.secondary">
                        To
                      </Typography>
                      <Typography variant="body1">
                        {recipientInfo?.username || recipientInfo?.name || 'Unknown Recipient'}
                      </Typography>
                      <Typography variant="body2" color="text.secondary">
                        {formData.recipientAddress.substring(0, 10)}...
                      </Typography>
                    </Grid>

                    <Grid item xs={12}>
                      <Divider sx={{ my: 1 }} />
                    </Grid>

                    <Grid item xs={6}>
                      <Typography variant="subtitle2" color="text.secondary">
                        Amount
                      </Typography>
                      <Typography variant="h6">
                        {formatCurrency(formData.amount, formData.currency)}
                      </Typography>
                    </Grid>

                    <Grid item xs={6}>
                      <Typography variant="subtitle2" color="text.secondary">
                        Fee
                      </Typography>
                      <Typography variant="body1">
                        {formatCurrency(estimatedFee, formData.currency)}
                      </Typography>
                    </Grid>

                    <Grid item xs={12}>
                      <Divider sx={{ my: 1 }} />
                    </Grid>

                    <Grid item xs={12}>
                      <Typography variant="subtitle2" color="text.secondary">
                        Total
                      </Typography>
                      <Typography variant="h5">
                        {formatCurrency(calculateTotal(), formData.currency)}
                      </Typography>
                    </Grid>

                    {formData.description && (
                      <Grid item xs={12}>
                        <Typography variant="subtitle2" color="text.secondary">
                          Description
                        </Typography>
                        <Typography variant="body1">
                          {formData.description}
                        </Typography>
                      </Grid>
                    )}
                  </Grid>
                </CardContent>
              </Card>

              <Alert severity="warning" sx={{ mb: 3 }}>
                Please review the transaction details carefully. All transactions are final and cannot be reversed.
              </Alert>
            </Box>
          )}

          <Box sx={{ display: 'flex', justifyContent: 'space-between', mt: 4 }}>
            <Button
              disabled={activeStep === 0}
              onClick={handleBack}
              variant="outlined"
            >
              Back
            </Button>
            <Button
              variant="contained"
              onClick={handleNext}
              endIcon={activeStep === steps.length - 1 ? <Send /> : null}
              disabled={
                wallets.length === 0 || 
                sendingFunds || 
                (activeStep === 0 && !formData.sourceWalletId)
              }
            >
              {sendingFunds ? (
                <>
                  <CircularProgress size={24} color="inherit" sx={{ mr: 1 }} />
                  Processing...
                </>
              ) : activeStep === steps.length - 1 ? (
                'Send Money'
              ) : (
                'Next'
              )}
            </Button>
          </Box>
        </Paper>
      </Box>
    </Container>
  );
};

export default SendMoney;
